public int[] fix45(int[] nums)
{
    for	(int i = 0; i < nums.length - 1; i++)
    {
        if (nums[i] == 4)
        {
            int k = 0;
            while	(nums[k] != 5)
            {
                k++;
            }
            nums[k] = nums[i+1];
            nums[i + 1] = 5;

        }
    }
    return nums;
}

public int countCode(String str)
{
    String strA = str;
    int x = strA.length() - 3;
    int count = 0;
    for (int i = 0; i < x; i++)
    {
        if (strA.substring(i, i+2).equals("co") && strA.substring(i+3, i+4).equals("e"))
        {
            count += 1;
        }
    }
    return count;
}

public String mixString(String a, String b)
{
    String mix="";
    int i=0;
    char cha=a.charAt(i);
    char chb=b.charAt(i);
    for(i=0; i+1<= a.length() && i+1<=b.length();i++)
    {
        mix= mix+cha+chb;
    }
    if (!a.substring(i).equals(a.length()) || !b.substring(i).
        equals(b.length()))
    {
        mix=mix+a.substring(i+1)+b.substring(i+1);
    }
    return mix;

}

public boolean xyBalance(String str)
{	
    int x = str.length();
    int i = 1;
    while (str.length() - i > 0)
    {
        if(str.substring(str.length()-i).equals("y"))
        {
            return true;
            break;
        }
        if(str.substring(str.length()-i).equals("x"))
        {
            return false;
            break;
        }
    }
}

