public boolean in1To10(int n, boolean outsideMode)
{
    if ((n >= 1 && n <= 10) && !outsideMode) {
        return true;
    } else if (outsideMode){
        if (n <= 1 || n >= 10) {
            return true;
        }
        return false;
    }
    return false;
}

